from flask import Flask, request, jsonify, Response
from flask_cors import CORS
import requests, os, json, sqlite3, threading, time, datetime

app = Flask(__name__)
CORS(app, origins="*")

CLAUDE_API_KEY = os.environ.get("CLAUDE_API_KEY", "")
WA_TOKEN      = os.environ.get("WA_TOKEN", "")
WA_PHONE_ID   = os.environ.get("WA_PHONE_ID", "")
VERIFY_TOKEN  = os.environ.get("VERIFY_TOKEN", "nicole2024")

CONVERSATIONS = {}
db_lock = threading.Lock()

def get_db():
    conn = sqlite3.connect("/tmp/nicole.db")
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as conn:
        conn.execute("""CREATE TABLE IF NOT EXISTS bookings (
            id INTEGER PRIMARY KEY,
            data TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )""")
        conn.commit()

init_db()

def load_bookings():
    with db_lock:
        with get_db() as conn:
            rows = conn.execute("SELECT data FROM bookings ORDER BY created_at ASC").fetchall()
            return [json.loads(r["data"]) for r in rows]

def save_booking(b):
    with db_lock:
        with get_db() as conn:
            existing = conn.execute("SELECT id FROM bookings WHERE id=?", (b["id"],)).fetchone()
            if existing:
                conn.execute("UPDATE bookings SET data=? WHERE id=?", (json.dumps(b), b["id"]))
            else:
                conn.execute("INSERT INTO bookings (id, data) VALUES (?,?)", (b["id"], json.dumps(b)))
            conn.commit()

def delete_booking(bid):
    with db_lock:
        with get_db() as conn:
            conn.execute("DELETE FROM bookings WHERE id=?", (bid,))
            conn.commit()

def replace_all_bookings(bookings_list):
    with db_lock:
        with get_db() as conn:
            conn.execute("DELETE FROM bookings")
            for b in bookings_list:
                conn.execute("INSERT INTO bookings (id, data) VALUES (?,?)", (b["id"], json.dumps(b)))
            conn.commit()

def send_wa_message(to, text):
    if not WA_TOKEN or not WA_PHONE_ID:
        return
    requests.post(
        "https://graph.facebook.com/v19.0/" + WA_PHONE_ID + "/messages",
        headers={"Authorization": "Bearer " + WA_TOKEN, "Content-Type": "application/json"},
        json={"messaging_product": "whatsapp", "to": to, "type": "text", "text": {"body": text}},
        timeout=10
    )

SYSTEM_PROMPT = """You are the AI wedding concierge for Nicole Please Weddings, a luxury celebrity and destination wedding planning company.

ABOUT: Based in Hong Kong and Zurich. Founded by Nicole Please. Plans weddings worldwide for international couples.
Notable weddings: actress Celina Jade and K-Pop star Han Geng (New Zealand), Saudi Arabian wedding at The Dolder Grand Zurich, Indian wedding in Hong Kong.

DESTINATIONS: Switzerland, Zermatt, New Zealand, Cappadocia, Hong Kong, Portugal, Ticino, Marrakech, Lucerne, Zurich + any custom destination.

SERVICES: Full wedding planning, destination weddings, elopements, proposals, multi-day celebrations, cross-cultural weddings.

CONTACT: WhatsApp +852 9721 0096 | calendly.com/nicolepleaseweddings | @nicolepleaseweddings | nicoleplease.com

PERSONALITY: Warm, elegant, inspiring. Paint beautiful pictures. Keep replies concise for WhatsApp.
PRICING: Never give specific prices. Say pricing depends on destination, guest count, and scope.

Collect: name, email, destination, approximate wedding date, number of guests, special requests.

When all info collected, add at end of message:
BOOKING_DATA:{"name":"VALUE","email":"VALUE","destination":"VALUE","date":"VALUE","guests":"VALUE","notes":"VALUE"}

Reply in the SAME language the client writes in."""

@app.route("/webhook", methods=["GET"])
def verify():
    mode      = request.args.get("hub.mode")
    token     = request.args.get("hub.verify_token")
    challenge = request.args.get("hub.challenge")
    if mode == "subscribe" and token == VERIFY_TOKEN:
        return challenge, 200
    return "Forbidden", 403

@app.route("/webhook", methods=["POST"])
def receive_message():
    try:
        data    = request.get_json()
        entry   = data.get("entry", [{}])[0]
        changes = entry.get("changes", [{}])[0]
        value   = changes.get("value", {})
        msgs    = value.get("messages", [])
        for msg in msgs:
            wa_id = msg.get("from")
            if msg.get("type") == "text":
                user_text = msg["text"]["body"]
                if wa_id not in CONVERSATIONS:
                    CONVERSATIONS[wa_id] = []
                CONVERSATIONS[wa_id].append({"role": "user", "content": user_text})
                if len(CONVERSATIONS[wa_id]) > 20:
                    CONVERSATIONS[wa_id] = CONVERSATIONS[wa_id][-20:]
                r = requests.post(
                    "https://api.anthropic.com/v1/messages",
                    headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
                    json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": SYSTEM_PROMPT, "messages": CONVERSATIONS[wa_id]},
                    timeout=30
                )
                reply = r.json().get("content", [{}])[0].get("text", "")
                if reply:
                    CONVERSATIONS[wa_id].append({"role": "assistant", "content": reply})
                    clean = reply[:reply.find("BOOKING_DATA:")].strip() if "BOOKING_DATA:" in reply else reply
                    send_wa_message(wa_id, clean)
                    if "BOOKING_DATA:" in reply:
                        try:
                            idx = reply.find("BOOKING_DATA:") + len("BOOKING_DATA:")
                            raw = reply[idx:].strip()
                            end_idx = raw.find("}") + 1
                            d = json.loads(raw[:end_idx])
                            bid = int(time.time() * 1000)
                            b = {
                                "id": bid,
                                "name": d.get("name", "Client"),
                                "email": d.get("email", ""),
                                "phone": "+" + wa_id,
                                "cruise": d.get("destination", d.get("cruise", "")),
                                "date": d.get("date", ""),
                                "guests": d.get("guests", ""),
                                "price": d.get("budget", ""),
                                "notes": d.get("notes", ""),
                                "status": "new",
                                "fromChat": True,
                                "createdAt": datetime.datetime.utcnow().isoformat()
                            }
                            save_booking(b)
                        except Exception as ex:
                            print("Booking parse error:", ex)
    except Exception as e:
        print("Webhook error:", e)
    return jsonify({"status": "ok"}), 200

@app.route("/bookings", methods=["GET"])
def get_bookings():
    return jsonify({"bookings": load_bookings()})

@app.route("/bookings", methods=["POST"])
def set_bookings():
    data = request.get_json()
    if data and "bookings" in data:
        replace_all_bookings(data["bookings"])
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["DELETE"])
def del_booking(bid):
    delete_booking(bid)
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["PUT"])
def update_booking(bid):
    b = request.get_json()
    if b:
        b["id"] = bid
        save_booking(b)
    return jsonify({"ok": True})

DASHBOARD_B64 = ""

@app.route("/", methods=["GET"])
def home():
    import base64 as b64mod
    return Response(b64mod.b64decode(DASHBOARD_B64).decode("utf-8"), mimetype="text/html")

@app.route("/chat", methods=["POST"])
def chat():
    try:
        data = request.get_json()
        r = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
            json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": data.get("system", ""), "messages": data.get("messages", [])},
            timeout=30
        )
        return jsonify(r.json()), r.status_code
    except Exception as e:
        return jsonify({"error": {"message": str(e)}}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 8080)))
